import React from 'react';
import '../../styles/Header.css';

function Header() {
  return (
    <header className="app-header">
      <nav className="nav-container">
        <ul className="nav-links">
          <li><a href="/">Home</a></li>
          <li><a href="/workouts">Workouts</a></li>
        </ul>
      </nav>
    </header>
  );
}

export default Header;
